@Test
public void testValidElitismRateBoundary() {
    final List<Chromosome> chromosomes = Collections.emptyList();
    ElitisticListPopulation pop1 = new ElitisticListPopulation(chromosomes, 100, 0.0);
    assertEquals(0.0, pop1.getElitismRate(), 0.0);
    ElitisticListPopulation pop2 = new ElitisticListPopulation(chromosomes, 100, 1.0);
    assertEquals(1.0, pop2.getElitismRate(), 0.0);
}

@Test
public void testValidElitismRateNonListConstructorBoundary() {
    ElitisticListPopulation pop1 = new ElitisticListPopulation(100, 0.0);
    assertEquals(0.0, pop1.getElitismRate(), 0.0);
    ElitisticListPopulation pop2 = new ElitisticListPopulation(100, 1.0);
    assertEquals(1.0, pop2.getElitismRate(), 0.0);
}

@Test(expected = IllegalArgumentException.class)
public void testChromosomeListConstructorJustAboveOne() {
    final List<Chromosome> chromosomes = Collections.emptyList();
    final double rate = 1.0001;
    new ElitisticListPopulation(chromosomes, 100, rate);
}

@Test(expected = IllegalArgumentException.class)
public void testConstructorJustBelowZero() {
    final double rate = -0.0001;
    new ElitisticListPopulation(100, rate);
}
